import{c as o,Q as l,j as i,m as t}from"./chunks/framework.BI6u8GL6.js";const h=JSON.parse('{"title":"更新日志","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/changelog.md","filePath":"zh/guide/changelog.md","lastUpdated":1783157055000}'),r={name:"zh/guide/changelog.md"};function c(a,e,d,n,s,u){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to &quot;更新日志&quot;">​</a></h1><p>所有显著变更均记录在本文件中。格式基于 <a href="https://keepachangelog.com/zh-CN/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>， 版本号遵循 <a href="https://semver.org/lang/zh-CN/" target="_blank" rel="noreferrer">语义化版本</a>。</p><h2 id="_1-3-0-2026-07-04" tabindex="-1">[1.3.0] - 2026-07-04 <a class="header-anchor" href="#_1-3-0-2026-07-04" aria-label="Permalink to &quot;[1.3.0] - 2026-07-04&quot;">​</a></h2><h3 id="新增" tabindex="-1">新增 <a class="header-anchor" href="#新增" aria-label="Permalink to &quot;新增&quot;">​</a></h3><ul><li><strong>executeWithCallbacks</strong> — <code>MergeSpec.executeWithCallbacks(em)</code> 先 flush 持久化上下文触发 JPA 生命周期回调后再执行原生 UPSERT</li><li><strong>多行 UPSERT 批处理</strong> — <code>MergeSpec.executeBatch()</code> 自动使用 <code>INSERT INTO ... VALUES (...), (...) ON CONFLICT ...</code> 多行语法（MySQL/PostgreSQL），方言不支持时回退逐行</li><li><strong>supportsBatchUpsert()</strong> — <code>DialectStrategy</code> 新增能力检测方法，<code>MergeSpec</code> 改用能力检查而非 try-catch</li><li><strong>SoftDeleteBulkExecutor</strong> — 从 <code>SoftDeleteHelper</code> 提取批量软删除操作（~450 行），Helper 降至 ~740 行，保留所有公共 API 委托保持向后兼容</li><li><strong>查询 Lambda 便捷重载</strong> — <code>MyJpaRepository</code> 和 <code>MyJpaTemplate</code> 新增 <code>Consumer&lt;QuerySpec&lt;T&gt;&gt;</code> Lambda 重载，无需 <code>new QuerySpec&lt;&gt;()</code><ul><li><code>findAll(consumer)</code>, <code>findOne(consumer)</code>, <code>count(consumer)</code>, <code>exists(consumer)</code></li><li><code>MyJpaTemplate</code> 同步新增对应 Lambda 重载</li></ul></li><li><strong>QuerySpec.of() 工厂方法</strong> — 新增 <code>QuerySpec.of(consumer)</code> 静态工厂方法，将 3 行创建代码简化为 1 行</li><li><strong>虚拟线程兼容性</strong> — <code>SoftDeleteContext</code> 和 <code>DefaultMyJpaRepository</code> 完全兼容 Java 21+ 虚拟线程 <ul><li>新增 <code>withIgnore(Runnable)</code> 和 <code>withIgnore(Supplier)</code> 便捷方法，自动管理生命周期</li><li>虚拟线程隔离性验证测试</li></ul></li><li><strong>UPSERT 方言扩展</strong> — <code>MergeSpec</code> 支持 4 种数据库方言 <ul><li>新增 <code>OracleDialect</code>（<code>MERGE INTO ... USING ... ON ... WHEN MATCHED/NOT MATCHED</code>）</li><li>新增 <code>SqlServerDialect</code>（<code>[方括号]</code> 转义 + <code>MERGE INTO</code>）</li><li><code>DialectDetector</code> 默认注册 postgresql、mysql、oracle、sqlserver 四种方言</li><li>新增 <code>removeDialect()</code> 运行时移除方言方法</li></ul></li><li><strong>聚合查询工具类</strong> — 新增 <code>QueryAggregates</code> 提供独立的 <code>count</code>/<code>sum</code>/<code>avg</code>/<code>max</code>/<code>min</code> 聚合表达式工厂方法</li><li><strong>softDeleteAll 行数保护</strong> — <code>SoftDeleteHelper.softDeleteAll()</code> 新增 <code>maxRows</code> 参数，默认最多更新 10000 行</li><li><strong>multiLike 嵌套字段校验</strong> — <code>multiLike(keyword, &quot;address.city&quot;)</code> 现在对每段调用 <code>IdentifierValidator.validateColumnName()</code> 进行安全校验</li><li><strong>EncryptConverter 事务清理</strong> — 新增 <code>registerTransactionCleanupIfNeeded()</code>，在事务中自动注册 <code>afterCompletion</code> 回调清理 Cipher ThreadLocal</li><li><strong>CacheAdapter SPI</strong> — 新增可插拔缓存适配器接口，支持注入 Redis/Caffeine 等分布式缓存 <ul><li>新增 <code>CacheAdapter</code> 接口、<code>DisabledCacheAdapter</code> 无操作实现</li><li><code>QueryCacheManager</code> 实现 <code>CacheAdapter</code>（向后兼容）</li><li><code>MyJpaTemplate</code> 内部使用 <code>CacheAdapter</code>，新增 <code>setCacheAdapter()</code>/<code>getCacheAdapter()</code></li></ul></li><li><strong>Java 模块系统兼容性</strong> — 完整的 <code>--add-opens</code> 修复指引</li><li><strong>Op.resolve() 策略模式</strong> — <code>Op</code> 枚举作为谓词构建的唯一真实来源</li></ul><h3 id="优化" tabindex="-1">优化 <a class="header-anchor" href="#优化" aria-label="Permalink to &quot;优化&quot;">​</a></h3><ul><li><strong>EncryptionKeyManager LRU 缓存淘汰</strong> — 密钥缓存从 FIFO 改为 LRU 策略</li><li><strong>SlowQueryDataSourceProxy 移除冗余锁</strong> — 直接使用 <code>SampledEvictionCache.computeIfAbsent()</code> 的原子性保证线程安全</li><li><strong>QuerySpec 拆分</strong> — 从 1265 行拆分为 887 行 + 7 个辅助类</li><li><strong>Deprecated API 清理</strong> — 移除 11 个废弃方法</li><li><strong>QuerySpec.copy() 性能优化</strong> — 空条件树使用快速路径，跳过深拷贝</li></ul><h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h3><ul><li><strong>EncryptConverter Cipher 对象池泄漏</strong> — 修复加密/解密失败路径中 Cipher 对象未归还到对象池的问题</li><li><strong>BulkOperationTemplate 迭代计数</strong> — 修复失败批次 iteration 双重递增问题</li><li><strong>MergeSpec 事务管理</strong> — 提取 <code>safeRollback()</code> 方法消除重复的 rollback 逻辑</li><li><strong>QuerySpec.copy() 深拷贝</strong> — 修复浅拷贝导致嵌套条件共享可变状态的问题</li><li><strong>NodeResolver LEFT JOIN 软删除过滤位置</strong> — 软删除条件从 WHERE 子句移至 ON 子句</li><li><strong>EncryptConverter GCM Cipher 生命周期</strong> — 移除 ThreadLocal Cipher 缓存，每次操作新建实例（JDK-8201324）</li><li><strong>CacheKeyBuilder 递归深度保护</strong> — 添加 128 层递归深度限制</li><li>另有 20+ 项缺陷修复（详见源码 CHANGELOG.md）</li></ul><h2 id="_1-2-0-2026-06-12" tabindex="-1">[1.2.0] - 2026-06-12 <a class="header-anchor" href="#_1-2-0-2026-06-12" aria-label="Permalink to &quot;[1.2.0] - 2026-06-12&quot;">​</a></h2><h3 id="新增-1" tabindex="-1">新增 <a class="header-anchor" href="#新增-1" aria-label="Permalink to &quot;新增&quot;">​</a></h3><ul><li><strong>UPSERT/MERGE 支持</strong> — <code>MergeSpec</code> 构建器，支持 PostgreSQL <code>ON CONFLICT</code>、MySQL <code>ON DUPLICATE KEY</code>、H2 <code>MERGE</code></li><li><strong>CTE 支持</strong> — <code>CteSpec</code> 支持普通和递归 Common Table Expression</li><li><strong>SQL 慢查询监控</strong> — <code>SqlSlowQueryInterceptor</code> + <code>myjpa-plus.monitoring</code> 配置</li><li><strong>字段加密</strong> — <code>@Encrypt</code> 注解 + <code>EncryptConverter</code>（AES/GCM，随机 IV）</li><li><strong>字段脱敏</strong> — <code>@Mask</code> 注解 + <code>MaskSerializer</code>（Jackson，支持 PHONE/EMAIL/ID_CARD/NAME）</li><li><strong>乐观锁自动重试</strong> — <code>@RetryOnOptimisticLock</code> 注解，指数退避</li><li><strong>查询结果缓存</strong> — <code>QueryCacheManager</code>，TTL 过期策略</li><li><strong>数据库函数调用</strong> — <code>func(field, functionName, comparisonOp, value)</code> 条件方法</li><li><strong>Case-insensitive 字符串查询</strong> — <code>eqIgnoreCase</code>、<code>neIgnoreCase</code>、<code>likeIgnoreCase</code></li><li><strong>多字段 LIKE 搜索</strong> — <code>multiLike(keyword, &quot;field1&quot;, &quot;field2&quot;)</code> 支持字符串字段名</li><li><strong>String 类型软删除</strong> — 支持 <code>@SoftDelete</code> 注解的 String 类型 deletedValue</li></ul><h3 id="变更" tabindex="-1">变更 <a class="header-anchor" href="#变更" aria-label="Permalink to &quot;变更&quot;">​</a></h3><ul><li><strong>移除 H2 数据库支持</strong> — 测试统一使用 MySQL</li><li><strong>移除 BaseEntity 类</strong> — 审计字段通过 <code>AuditEntityListener</code> 自动填充</li><li><strong>重构实体字段提取和方言检测</strong></li><li><strong>重构批量操作模板</strong> — 优化事务管理和内存控制</li><li><strong>重构条件构建器接口</strong> — 拆分为 8 个子接口</li></ul><h3 id="修复-1" tabindex="-1">修复 <a class="header-anchor" href="#修复-1" aria-label="Permalink to &quot;修复&quot;">​</a></h3><ul><li><strong>not() 语义一致性</strong> — 修复否定条件组的语义问题</li><li><strong>缓存驱逐</strong> — 修复批量操作中的缓存驱逐问题</li><li><strong>LIKE 通配符转义</strong> — 修复 <code>likeSafe()</code> 的通配符转义问题</li><li><strong>null 校验统一</strong> — 统一条件方法的 null 校验逻辑</li></ul><h2 id="_1-1-0-2026-05-31" tabindex="-1">[1.1.0] - 2026-05-31 <a class="header-anchor" href="#_1-1-0-2026-05-31" aria-label="Permalink to &quot;[1.1.0] - 2026-05-31&quot;">​</a></h2><h3 id="新增-2" tabindex="-1">新增 <a class="header-anchor" href="#新增-2" aria-label="Permalink to &quot;新增&quot;">​</a></h3><ul><li><strong>枚举转换支持</strong> — <code>@CodeEnum</code> + <code>@CodeEnumValue</code> 注解解决 Hibernate 6 枚举映射问题 <ul><li>支持 CHAR(1) 存储枚举编码（如 &#39;0&#39;、&#39;1&#39;、&#39;M&#39;、&#39;F&#39;）</li><li>支持 int、long、String 类型的 code 字段</li><li>无需创建转换器类，只需在枚举和实体字段上添加注解</li></ul></li><li><strong>multiLike 支持字符串字段名</strong> — <code>multiLike(keyword, &quot;field1&quot;, &quot;field2&quot;)</code> 适用于动态字段名场景</li><li><strong>软删除 Integer 类型支持</strong> — <code>@SoftDelete(deletedIntValue = 1)</code> 支持用整数值标记删除状态</li><li><strong>MyJpaTemplate.count() 方法</strong> — 新增便捷的计数方法</li><li><strong>聚合函数 API</strong> — 新增聚合查询功能</li></ul><h3 id="变更-1" tabindex="-1">变更 <a class="header-anchor" href="#变更-1" aria-label="Permalink to &quot;变更&quot;">​</a></h3><ul><li><code>ConditionBuilder</code> 添加 <code>notBetween</code> 和 <code>likeIgnoreCase</code> 的条件变体</li><li><code>SubQuerySpec</code> 和 <code>AbstractBulkOperationSpec</code> 添加更多条件便捷方法</li><li>优化 <code>LambdaUtils</code> 缓存驱逐策略，使用 CAS 操作避免竞态条件</li><li>优化 <code>InClauseBuilder</code> 批次处理，避免内存泄漏</li></ul><h3 id="修复-2" tabindex="-1">修复 <a class="header-anchor" href="#修复-2" aria-label="Permalink to &quot;修复&quot;">​</a></h3><ul><li>修复 EXISTS 子查询关联限制，支持从 Join 路径关联</li><li>修复 <code>MyJpaTemplate.findAllStream</code> 废弃策略</li><li>修复 <code>DefaultMyJpaRepository.deleteById</code> 方法，正确处理软删除实体</li></ul><h2 id="_1-0-0-2026-05-28" tabindex="-1">[1.0.0] - 2026-05-28 <a class="header-anchor" href="#_1-0-0-2026-05-28" aria-label="Permalink to &quot;[1.0.0] - 2026-05-28&quot;">​</a></h2><h3 id="破坏性变更" tabindex="-1">破坏性变更 <a class="header-anchor" href="#破坏性变更" aria-label="Permalink to &quot;破坏性变更&quot;">​</a></h3><ul><li><code>DeleteSpec</code> 现在要求显式 WHERE 条件</li><li>修复 <code>resolveOr()</code> 空分组语义</li></ul><h3 id="新增-3" tabindex="-1">新增 <a class="header-anchor" href="#新增-3" aria-label="Permalink to &quot;新增&quot;">​</a></h3><ul><li><code>eqIgnoreCase</code> / <code>likeIgnoreCase</code> — 不区分大小写的字符串条件</li><li><code>groupBy(SFunction...)</code> — GROUP BY 子句支持</li><li><code>having(BiFunction)</code> — HAVING 子句</li><li><code>not(Consumer)</code> — 否定条件组</li><li><code>startsWith</code> / <code>endsWith</code> / <code>contains</code> — 便捷 LIKE 方法</li><li>Consumer 模式：<code>or(Consumer)</code> / <code>join(field, Consumer)</code> / <code>leftJoin(field, Consumer)</code></li><li>Spring Boot 自动配置</li><li><code>ProjectionSpec</code> — DTO 投影查询</li><li><code>MyJpaTemplate</code> 流式 API 和批量操作</li><li><code>EntityGraphHelper</code> — 动态 JPA EntityGraph 构建器</li><li><code>PageableHelper</code> — QuerySpec/Pageable 排序集成</li></ul><h3 id="修复-3" tabindex="-1">修复 <a class="header-anchor" href="#修复-3" aria-label="Permalink to &quot;修复&quot;">​</a></h3><ul><li><code>SubQuerySpec</code> 条件不再互相覆盖</li><li><code>SoftDeleteHelper.findSoftDeleteField()</code> 竞态条件修复</li></ul><h2 id="_0-0-2-2026-05-28" tabindex="-1">[0.0.2] - 2026-05-28 <a class="header-anchor" href="#_0-0-2-2026-05-28" aria-label="Permalink to &quot;[0.0.2] - 2026-05-28&quot;">​</a></h2><h3 id="新增-4" tabindex="-1">新增 <a class="header-anchor" href="#新增-4" aria-label="Permalink to &quot;新增&quot;">​</a></h3><ul><li><strong>批量操作 LIMIT 支持</strong> — <code>executeWithMaxRows()</code> 方法</li><li><strong>大型 IN 子句处理</strong> — 自动拆分超过数据库参数限制的 IN 子句</li><li><strong>GroupBy + Having 支持</strong> — <code>groupBy(SFunction...)</code> 和 <code>having(BiFunction)</code></li><li><strong>SubQuerySpec 关联</strong> — <code>correlate(root)</code> 支持子查询关联</li><li><strong>Spring Boot 自动配置</strong> — 自动注册 <code>MyJpaTemplate</code> 和相关组件</li></ul><h2 id="_0-0-1-2026-05-26" tabindex="-1">[0.0.1] - 2026-05-26 <a class="header-anchor" href="#_0-0-1-2026-05-26" aria-label="Permalink to &quot;[0.0.1] - 2026-05-26&quot;">​</a></h2><h3 id="初始发布" tabindex="-1">初始发布 <a class="header-anchor" href="#初始发布" aria-label="Permalink to &quot;初始发布&quot;">​</a></h3><ul><li>基于 Lambda API 的类型安全 JPA <code>Specification</code> 构建器</li><li><code>QuerySpec&lt;T&gt;</code>：eq, ne, gt, ge, lt, le, like, notLike, in, notIn, between, isNull, isNotNull</li><li>JOIN 支持：<code>join()</code>、<code>leftJoin()</code> 配合 <code>JoinGroup</code></li><li>OR 分组：<code>or()</code> 配合 <code>OrGroup</code></li><li>EXISTS 子查询配合 <code>SubQuerySpec</code></li><li>通过 <code>multiLike</code> 实现多字段 LIKE 搜索</li><li>针对 Hibernate 延迟代理的 Jackson 序列化器</li></ul>',36)])])}const p=o(r,[["render",c]]);export{h as __pageData,p as default};
